function removeNthNodeFromEndOfList(data) {
    const lines = data.trim().split('\n');
    const values = lines[0].split(' ').map(Number);
    const n = Number(lines[1]);

    const length = values.length;
    if (length === 0 || n > length) return values.join(' ');

    const positionToRemove = length - n;
    values.splice(positionToRemove, 1);
    return values.join(' ');
}

