class Solution {
    public ListNode removeNthNodeFromEndOfList(ListNode head) {
        if (head == null) return null;
        int length = 0;
        ListNode current = head;
        while (current != null) {
            length++;
            current = current.next;
        }
        if (length == 1) return null;
        int target = length - 1;
        current = head;
        ListNode prev = null;
        for (int i = 0; i < target; i++) {
            prev = current;
            current = current.next;
        }
        if (prev != null) {
            prev.next = current.next;
        }
        else {
            head = head.next;
        }
        return head;
    }
}

