package main

type ListNode struct {
    Val  int
    Next *ListNode
}

func removeNthNodeFromEndOfList(head *ListNode, n int) *ListNode {
    if head == nil {
        return nil
    }

    count := 0
    current := head
    for current != nil {
        count++
        current = current.Next
    }

    if n > count {
        return head
    }

    if n == count {
        return head.Next
    }

    position := count - n
    current = head
    for position > 1 {
        current = current.Next
        position--
    }

    current.Next = current.Next.Next
    return head
}

