class Solution {
    public:
    ListNode* removeNthNodeFromEndOfList(ListNode* head, int n) {
        ListNode* first = head;
        ListNode* second = head;
        ListNode* prev = nullptr;
        for (int i = 0; i < n; i++) {
            if (first == nullptr) return head; // n is larger than the length of the list
            first = first->next;
        }
        while (first != nullptr) {
            prev = second;
            second = second->next;
            first = first->next;
        }
        if (prev == nullptr) {
            // Remove the head
            ListNode* newHead = head->next;
            delete head;
            return newHead;
        }
        else {
            prev->next = second->next;
            delete second;
            return head;
        }
    }
}
